/**
 * One-off generator: emits data/tools-awesome-oss-systems.ts from structured rows.
 * Run: node scripts/gen-awesome-oss-tools.mjs
 */
import { writeFileSync } from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

/** @typedef {'top-pick'|'also-strong'|'honorable'} Rank */

/**
 * @param {object} o
 * @returns {string}
 */
function toolBlock(o) {
  const rank = o.rank ?? "honorable";
  const maint = o.maintenanceStatus ?? "active";
  const mat = o.maturity ?? "established";
  const plat = JSON.stringify(o.platforms ?? ["Web", "Self-hosted", "Cross-platform"]);
  const strengths = JSON.stringify(o.strengths ?? ["Open source", "Transparent development"]);
  const lim = JSON.stringify(o.limitations ?? ["Verify license fit for your deployment"]);
  const alts = JSON.stringify(o.alternatives ?? []);
  const tags = JSON.stringify(o.tags ?? []);
  const why =
    o.whyIncluded ??
    "Listed in [awesome-open-source-systems](https://github.com/ishanvyas22/awesome-open-source-systems) and aligned with this catalog’s focus on usable FOSS systems.";
  const lines = [
    "  {",
    `    slug: ${JSON.stringify(o.slug)},`,
    `    name: ${JSON.stringify(o.name)},`,
    `    categorySlug: ${JSON.stringify(o.categorySlug)},`,
    `    summary: ${JSON.stringify(o.summary)},`,
    `    whyIncluded: ${JSON.stringify(why)},`,
    `    bestFor: ${JSON.stringify(o.bestFor ?? "Teams evaluating open tools in this category.")},`,
    `    platforms: ${plat},`,
    `    license: ${JSON.stringify(o.license ?? "See upstream repository (FOSS components vary by build)")},`,
    `    maintenanceStatus: ${JSON.stringify(maint)},`,
    `    maturity: ${JSON.stringify(mat)},`,
    `    strengths: ${strengths},`,
    `    limitations: ${lim},`,
    `    alternatives: ${alts},`,
    `    officialSite: ${JSON.stringify(o.officialSite)},`,
    `    sourceRepo: ${JSON.stringify(o.sourceRepo ?? o.officialSite)},`,
    `    tags: ${tags},`,
    `    rank: ${JSON.stringify(rank)},`,
  ];
  if (o.privacyFocused) lines.push(`    privacyFocused: true,`);
  if (o.selfHosted) lines.push(`    selfHosted: true,`);
  if (o.developerFocused) lines.push(`    developerFocused: true,`);
  if (o.beginnerFriendly) lines.push(`    beginnerFriendly: true,`);
  if (o.relatedSlugs?.length)
    lines.push(`    relatedSlugs: ${JSON.stringify(o.relatedSlugs)},`);
  lines.push("  },");
  return lines.join("\n");
}

